            foreach ($rootRows as $row) {
                DB::table('accnt_charts')->updateOrInsert(
                    [
                        'company_id' => $companyId,
                        'work_point_id' => $workPointId,
                        'AccCode' => $row['code'],
                    ],
                    [
                        'AccDescription' => $row['name'],
                        'AccType' => $row['type'],
                        'Status' => $status,
                        'created_at' => $now,
                        'updated_at' => $now,
                    ]
                );
            }

            $chartIds = DB::table('accnt_charts')
                ->where('company_id', $companyId)
                ->where('work_point_id', $workPointId)
                ->pluck('id', 'AccCode');

            foreach (array_chunk($subRows, 500) as $chunk) {
                foreach ($chunk as $row) {
                    if (!isset($chartIds[$row['root']])) {
                        continue;
                    }

                    DB::table('accnt_subcharts')->updateOrInsert(
                        [
                            'company_id' => $companyId,
                            'work_point_id' => $workPointId,
                            'accnt_chart_id' => $chartIds[$row['root']],
                            'SubCode' => $row['code'],
                        ],
                        [
                            'SubDescription' => $row['name'],
                            'Status' => $status,
                            'created_at' => $now,
                            'updated_at' => $now,
                        ]
                    );
                }
